{"filePath":"/home/runner/coba_ppt/fix_pptx_zip.js","content":"#!/usr/bin/env node
/**
 * fix_pptx_zip.js — Post-processing fix untuk PptxGenJS output
 *
 * Masalah: PptxGenJS menulis [Content_Types].xml sebagai entry ke-19
 * dalam ZIP, bukan entry pertama. PowerPoint (Microsoft) strict terhadap
 * ECMA-376 OPC spec yang mensyaratkan [Content_Types].xml sebagai part
 * pertama dalam package.
 *
 * Fix: Baca file PPTX, tulis ulang dengan [Content_Types].xml sebagai
 * entry ZIP pertama, baru disusul entry lain.
 *
 * Penggunaan:
 *   node fix_pptx_zip.js <input.pptx> [output.pptx]
 *
 * Jika output tidak disebutkan, file input akan di-overwrite.
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

// ─── Konfigurasi ───
const inputFile = process.argv[2];
const outputFile = process.argv[3] || inputFile;

if (!inputFile) {
  console.error("❌ Usage: node fix_pptx_zip.js <input.pptx> [output.pptx]");
  process.exit(1);
}

if (!fs.existsSync(inputFile)) {
  console.error(`❌ File not found: ${inputFile}`);
  process.exit(1);
}

// ─── Implementasi ───
const JSZip = require("jszip");

async function fixPptxZip() {
  try {
    // Baca file asli
    const data = fs.readFileSync(inputFile);
    const zip = await JSZip.loadAsync(data);

    // Cek apakah [Content_Types].xml ada
    if (!zip.files["[Content_Types].xml"]) {
      console.error("❌ [Content_Types].xml not found in ZIP!");
      process.exit(1);
    }

    // Cek posisi saat ini
    const currentOrder = Object.keys(zip.files);
    const ctPos = currentOrder.indexOf("[Content_Types].xml");
    console.log(`📦 Current [Content_Types].xml position: ${ctPos}`);

    if (ctPos === 0) {
      console.log("✅ [Content_Types].xml already first — no fix needed.");
      return;
    }

    // Tulis ulang ZIP dengan urutan baru
    const JSZipOut = require("jszip");
    const outZip = new JSZipOut();

    // 1. [Content_Types].xml PERTAMA
    const ctContent = await zip.files["[Content_Types].xml"].async("nodebuffer");
    outZip.file("[Content_Types].xml", ctContent);

    // 2. Semua entry lain (abaikan folder)
    for (const name of currentOrder) {
      if (name === "[Content_Types].xml") continue;
      if (name.endsWith("/")) continue; // skip folder entries

      const file = zip.files[name];
      const content = await file.async("nodebuffer");
      outZip.file(name, content);
    }

    // Generate ZIP
    const outBuffer = await outZip.generateAsync({
      type: "nodebuffer",
      compression: "DEFLATE",
      compressionOptions: { level: 6 },
    });

    // Tulis output
    const tmpFile = outputFile + ".tmp";
    fs.writeFileSync(tmpFile, outBuffer);

    // Verifikasi entry pertama
    const verifyZip = await JSZip.loadAsync(fs.readFileSync(tmpFile));
    const verifyOrder = Object.keys(verifyZip.files);
    const verifyCtPos = verifyOrder.indexOf("[Content_Types].xml");

    if (verifyCtPos !== 0) {
      console.error(`❌ Fix gagal! [Content_Types].xml masih di posisi ${verifyCtPos}`);
      fs.unlinkSync(tmpFile);
      process.exit(1);
    }

    // Ganti file asli
    if (tmpFile !== outputFile) {
      if (outputFile === inputFile) {
        fs.unlinkSync(inputFile);
      }
      fs.renameSync(tmpFile, outputFile);
    }

    const origSize = data.length;
    const newSize = outBuffer.length;
    console.log(`✅ Fixed! [Content_Types].xml now at position 0`);
    console.log(`   File: ${path.basename(outputFile)}`);
    console.log(`   Size: ${(origSize / 1024).toFixed(0)}KB → ${(newSize / 1024).toFixed(0)}KB`);

  } catch (err) {
    console.error(`❌ Error: ${err.message}`);
    process.exit(1);
  }
}

fixPptxZip();
"}

